solution_code:
#include <iostream>

template <typename T>
class Pair {
    T m_first;
    T m_second;
public:
    Pair(T a, T b) : m_first{a}, m_second{b} {}

    bool operator==(const Pair& rhs) const {
        return m_first == rhs.m_first && m_second == rhs.m_second;
    }

    bool operator!=(const Pair& rhs) const {
        return !(*this == rhs);
    }
};

int main() {
    int a1, a2, b1, b2;
    std::cin >> a1 >> a2 >> b1 >> b2;
    Pair<int> A{a1, a2};
    Pair<int> B{b1, b2};
    std::cout << "equal: "     << (A == B) << '\n';
    std::cout << "not_equal: " << (A != B) << '\n';
    return 0;
}

