solution_code:
#include <iostream>

template <typename T>
T findMax(const T* arr, int size) {
    T best = arr[0];
    for (int i = 1; i < size; ++i) {
        if (arr[i] > best)
            best = arr[i];
    }
    return best;
}

int main() {
    int n;
    std::cin >> n;
    int arr[10];
    for (int i = 0; i < n; ++i) std::cin >> arr[i];
    std::cout << "max: " << findMax(arr, n) << '\n';
    return 0;
}
